import re
import math
from dataclasses import dataclass, field

@dataclass
class ReActStep:
    """One step in the ReAct trajectory."""
    step_num: int
    thought: str
    action: str
    observation: str

@dataclass
class ReActResult:
    """Result of a ReAct agent run."""
    question: str
    answer: str
    trajectory: list  # list of ReActStep
    steps_taken: int
    finished: bool

class ReActAgent:
    def __init__(self):
        self.tools = {}

    def register_tool(self, name: str, func, description: str) -> None:
        self.tools[name] = {"func": func, "description": description}

    def parse_action(self, action_str: str) -> tuple:
        match = re.match(r'(\w+)\((.*)\)', action_str.strip())
        if not match:
            return (None, None)
        tool_name = match.group(1)
        argument = match.group(2).strip().strip("'\"")
        return (tool_name, argument)

    def execute_action(self, action_str: str) -> str:
        tool_name, argument = self.parse_action(action_str)
        if tool_name is None:
            return f"Error: Could not parse action '{action_str}'"
        if tool_name not in self.tools:
            return f"Error: Unknown tool '{tool_name}'. Available: {list(self.tools.keys())}"
        try:
            result = self.tools[tool_name]["func"](argument)
            return str(result)
        except Exception as e:
            return f"Error executing {tool_name}: {e}"

    def think(self, question: str, history: list) -> tuple:
        past_actions = [step.action for step in history]
        past_observations = [step.observation for step in history]
        has_searched = any("search(" in a for a in past_actions)
        has_calculated = any("calculator(" in a for a in past_actions)

        # Check if there's a math expression in the question
        has_math = bool(re.search(r'\d+\s*[+\-*/]\s*\d+|\d+\s*\*\*\s*\d+', question))
        math_match = re.search(r'(\d+[\s+\-*/.**\d]+)', question)

        # Determine non-stopwords for search
        stopwords = {"what", "is", "the", "a", "an", "of", "in", "and", "or", "how",
                     "many", "much", "does", "do", "can", "about", "tell", "me",
                     "find", "calculate", "compute"}
        words = re.findall(r'[a-zA-Z]+', question.lower())
        topic_words = [w for w in words if w not in stopwords and len(w) > 2]

        if has_math and not has_calculated and math_match:
            expr = math_match.group(1).strip()
            thought = f"The question involves a calculation: {expr}. I'll use the calculator."
            action = f"calculator({expr})"
        elif topic_words and not has_searched:
            topic = topic_words[0]
            thought = f"I need to look up information about '{topic}'."
            action = f"search({topic})"
        else:
            # Gather observations to form an answer
            obs_text = "; ".join(o for o in past_observations if not o.startswith("Error"))
            if obs_text:
                thought = f"I have gathered enough information. Observations: {obs_text}"
                action = f"finish({obs_text})"
            else:
                thought = "I could not find relevant information."
                action = "finish(No answer found)"

        return (thought, action)

    def run(self, question: str, max_steps: int = 10) -> ReActResult:
        history = []
        answer = ""
        finished = False

        for step_num in range(1, max_steps + 1):
            thought, action = self.think(question, history)
            tool_name, _ = self.parse_action(action)

            if tool_name == "finish":
                _, ans = self.parse_action(action)
                observation = "Done"
                step = ReActStep(step_num, thought, action, observation)
                history.append(step)
                answer = ans
                finished = True
                break

            observation = self.execute_action(action)
            step = ReActStep(step_num, thought, action, observation)
            history.append(step)

        return ReActResult(
            question=question,
            answer=answer,
            trajectory=history,
            steps_taken=len(history),
            finished=finished,
        )

# === Set up tools ===
def calculator(expression: str) -> str:
    try:
        result = eval(expression, {"__builtins__": {}, "math": math})
        return str(result)
    except Exception as e:
        return f"Error: {e}"

def search(topic: str) -> str:
    knowledge = {
        "python": "Python is a programming language created by Guido van Rossum in 1991.",
        "earth": "Earth has a radius of 6371 km and is the third planet from the Sun.",
        "transformer": "The Transformer architecture was introduced in 'Attention Is All You Need' (2017).",
        "gravity": "Gravitational acceleration on Earth is approximately 9.81 m/s^2.",
    }
    for key, value in knowledge.items():
        if key in topic.lower():
            return value
    return f"No results found for: {topic}"

agent = ReActAgent()
agent.register_tool("calculator", calculator, "Evaluate a math expression")
agent.register_tool("search", search, "Search for information on a topic")
agent.register_tool("finish", lambda answer: answer, "Finish with the final answer")

