from dataclasses import dataclass, field
from typing import Any, Callable
import math

TYPE_MAP = {
    "string": str,
    "integer": int,
    "float": (int, float),
    "boolean": bool,
}

class ToolRegistry:
    def __init__(self):
        self._tools = {}

    def register(self, name: str, func: Callable, schema: dict) -> None:
        if name in self._tools:
            raise ValueError(f"Tool '{name}' is already registered")
        self._tools[name] = {"func": func, "schema": schema}

    def validate(self, name: str, arguments: dict) -> list:
        errors = []
        if name not in self._tools:
            errors.append(f"Unknown tool: '{name}'")
            return errors

        schema = self._tools[name]["schema"]
        properties = schema.get("properties", {})

        # Check required parameters
        for param_name, param_schema in properties.items():
            if param_schema.get("required", False) and param_name not in arguments:
                errors.append(f"Missing required parameter: '{param_name}'")

        # Check for unknown parameters
        valid_params = set(properties.keys())
        for key in arguments:
            if key not in valid_params:
                errors.append(f"Unknown parameter: '{key}'")

        # Type checking
        for key, value in arguments.items():
            if key in properties:
                expected_type_str = properties[key].get("type", "string")
                expected_type = TYPE_MAP.get(expected_type_str, str)
                if not isinstance(value, expected_type):
                    errors.append(
                        f"Type error for '{key}': expected {expected_type_str}, got {type(value).__name__}"
                    )

        return errors

    def dispatch(self, name: str, arguments: dict) -> dict:
        errors = self.validate(name, arguments)
        if errors:
            return {"success": False, "result": None, "errors": errors}
        try:
            func = self._tools[name]["func"]
            result = func(**arguments)
            return {"success": True, "result": result, "errors": []}
        except Exception as e:
            return {"success": False, "result": None, "errors": [f"Execution error: {str(e)}"]}

    def list_tools(self) -> list:
        return [
            {
                "name": name,
                "description": info["schema"].get("description", ""),
                "parameters": info["schema"].get("properties", {}),
            }
            for name, info in self._tools.items()
        ]

    def get_tool_names(self) -> list:
        return sorted(self._tools.keys())

# === Create and populate registry ===
registry = ToolRegistry()

registry.register(
    "calculator",
    lambda expression: eval(expression, {"__builtins__": {}, "math": math}),
    {
        "description": "Evaluate a mathematical expression",
        "properties": {
            "expression": {"type": "string", "description": "Math expression", "required": True}
        },
    },
)

registry.register(
    "string_length",
    lambda text: len(text),
    {
        "description": "Get the length of a string",
        "properties": {
            "text": {"type": "string", "description": "Input string", "required": True}
        },
    },
)

registry.register(
    "power",
    lambda base, exponent: base ** exponent,
    {
        "description": "Raise a number to a power",
        "properties": {
            "base": {"type": "float", "description": "The base number", "required": True},
            "exponent": {"type": "integer", "description": "The exponent", "required": True},
        },
    },
)

from dataclasses import dataclass, field
from collections import deque

@dataclass
class Message:
    role: str
    content: str
    importance: float = 0.5

class ConversationMemory:
    def __init__(self, window_size: int = 10, max_summaries: int = 5):
        self.window_size = window_size
        self.max_summaries = max_summaries
        self.window: list = []
        self.summaries: list = []
        self.total_messages_added = 0

    def add_message(self, role: str, content: str, importance: float = 0.5) -> None:
        if len(self.window) >= self.window_size:
            self.summarize_window()
        self.window.append(Message(role, content, importance))
        self.total_messages_added += 1

    def summarize_window(self) -> str:
        if not self.window:
            return ""
        half = max(len(self.window) // 2, 1)
        to_summarize = self.window[:half]
        self.window = self.window[half:]

        summary = " | ".join(msg.content for msg in to_summarize)

        self.summaries.append(summary)
        if len(self.summaries) > self.max_summaries:
            self.summaries = self.summaries[-self.max_summaries:]

        return summary

    def get_context(self) -> dict:
        return {
            "summaries": list(self.summaries),
            "recent": [{"role": msg.role, "content": msg.content} for msg in self.window],
        }

    def get_token_estimate(self) -> int:
        tokens = 0
        for msg in self.window:
            tokens += len(msg.content.split())
        for summary in self.summaries:
            tokens += len(summary.split())
        return tokens

    def clear(self) -> None:
        self.window = []
        self.summaries = []
        self.total_messages_added = 0

memory = ConversationMemory(window_size=6, max_summaries=3)
